SELECT * 
FROM stock_options 
WHERE implied_volatility > (SELECT AVG(implied_volatility) FROM stock_options);

SELECT AVG(implied_volatility) as avg_implied_volatility, MAX(implied_volatility) as max_implied_volatility
FROM stock_options
WHERE volume > 5000;

SELECT symbol, expiry_date, strike_price
FROM stock_options
WHERE volume = (SELECT MAX(volume) FROM stock_options);

SELECT symbol
FROM stock_options
WHERE type_option_type = 'OPTSTK PE' AND strike_price > 200;

SELECT *
FROM stock_options
WHERE symbol = 'AAPL' AND type_option_type = 'PE';

SELECT symbol, current_price
FROM stock_options
ORDER BY current_price DESC;
